kernel_src="""
#include "kernel_operator.h"

constexpr int32_t BUFFER_NUM = 2;

class KernelLogSoftmaxCustom {
public:
    __aicore__ inline KernelLogSoftmaxCustom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y, GM_ADDR workspace,
                                uint32_t totalLength, uint32_t tileLength,
                                uint32_t blockDim, uint32_t dim)
    {
        totalLen_ = totalLength;
        tileLen_ = tileLength;
        blockDim_ = blockDim;
        dim_ = dim;
        batchSize_ = totalLen_ / dim_;

        xGm_.SetGlobalBuffer((__gm__ float*)x, totalLen_);
        yGm_.SetGlobalBuffer((__gm__ float*)y, totalLen_);
        workspaceGm_.SetGlobalBuffer((__gm__ float*)workspace, batchSize_ * 2);

        pipe_.InitBuffer(inQueueX_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(outQueueY_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(tmpQueue_, 1, tileLen_ * sizeof(float));
    }

    __aicore__ inline void Process()
    {
        if (totalLen_ == 0 || tileLen_ == 0) return;

        const uint32_t blockIdx = static_cast<uint32_t>(AscendC::GetBlockIdx());

        // Each block processes rows at stride blockDim_
        // Row index start: blockIdx, then + blockDim_ each step
        for (uint32_t row = blockIdx; row < batchSize_; row += blockDim_) {
            // Phase 1: compute max of the row
            float rowMax = -FLT_MAX;
            uint32_t rowStart = row * dim_;
            uint32_t remaining = dim_;
            uint32_t offset = rowStart;
            while (remaining > 0) {
                uint32_t curLen = (remaining > tileLen_) ? tileLen_ : remaining;
                // Load tile
                AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
                AscendC::DataCopy(xLocal, xGm_[offset], curLen);
                // Compute max
                float tileMax;
                AscendC::ReduceMax(tileMax, xLocal, curLen);
                if (tileMax > rowMax) rowMax = tileMax;
                inQueueX_.FreeTensor(xLocal);
                offset += curLen;
                remaining -= curLen;
            }
            // Write max to workspace
            workspaceGm_[row] = rowMax;

            // Phase 2: compute sum of exp(x - max) and write sum to workspace
            float rowSum = 0.0f;
            offset = rowStart;
            remaining = dim_;
            while (remaining > 0) {
                uint32_t curLen = (remaining > tileLen_) ? tileLen_ : remaining;
                AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
                AscendC::DataCopy(xLocal, xGm_[offset], curLen);
                AscendC::LocalTensor<float> tLocal = tmpQueue_.AllocTensor<float>();
                // t = x - max
                AscendC::Sub(tLocal, xLocal, rowMax, curLen);
                // t = exp(x - max)
                AscendC::Exp(tLocal, tLocal, curLen);
                // sum
                float tileSum;
                AscendC::ReduceSum(tileSum, tLocal, curLen);
                rowSum += tileSum;
                tmpQueue_.FreeTensor(tLocal);
                inQueueX_.FreeTensor(xLocal);
                offset += curLen;
                remaining -= curLen;
            }
            workspaceGm_[batchSize_ + row] = rowSum;

            // Phase 3: compute output y = x - max - log(sum)
            float logSum = logf(rowSum);
            offset = rowStart;
            remaining = dim_;
            while (remaining > 0) {
                uint32_t curLen = (remaining > tileLen_) ? tileLen_ : remaining;
                AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
                AscendC::DataCopy(xLocal, xGm_[offset], curLen);
                AscendC::LocalTensor<float> yLocal = outQueueY_.AllocTensor<float>();
                // y = x - max - logSum
                AscendC::Sub(yLocal, xLocal, rowMax, curLen);
                AscendC::Sub(yLocal, yLocal, logSum, curLen);
                AscendC::DataCopy(yGm_[offset], yLocal, curLen);
                outQueueY_.FreeTensor(yLocal);
                inQueueX_.FreeTensor(xLocal);
                offset += curLen;
                remaining -= curLen;
            }
        }
    }

private:
    AscendC::TPipe pipe_;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> inQueueX_;
    AscendC::TQue<AscendC::TPosition::VECOUT, BUFFER_NUM> outQueueY_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> tmpQueue_;

    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> yGm_;
    AscendC::GlobalTensor<float> workspaceGm_;

    uint32_t totalLen_ {0};
    uint32_t tileLen_ {0};
    uint32_t blockDim_ {0};
    uint32_t dim_ {1};
    uint32_t batchSize_ {0};
};

extern "C" __global__ __aicore__ void log_softmax_custom(GM_ADDR x, GM_ADDR y, GM_ADDR workspace, GM_ADDR tiling)
{
    GET_TILING_DATA(tiling_data, tiling);
    KernelLogSoftmaxCustom op;
    op.Init(x, y, workspace,
            tiling_data.totalLength,
            tiling_data.tileLength,
            tiling_data.blockDim,
            tiling_data.dim);
    op.Process();
}
